sys_script_include.script:
var IncentIQOrchestrator = Class.create();

IncentIQOrchestrator.prototype = {

    initialize: function() {

        this.payoutHandler =
            new IncentNowPayoutHandler();

        this.quotaHandler =
            new IncentNowQuotaHandler();

        this.planHandler =
            new IncentNowPlanHandler();

        this.utils = new IncentIQUtils();

    },

    execute: function(
        intent,
        userId,
        query
    ) {

        gs.info(
            "INCENTIQ_ORCHESTRATOR :: INTENT = " +
            intent
        );

        switch (intent) {

            // ==========================
            // PAYOUT DOMAIN
            // ==========================

            case "payout":

                return this.payoutHandler
                    .handlePayout(
                        userId,
                        query
                    );

            case "monthly_payout":

                return this.payoutHandler
                    .handleMonthlyPayout(
                        userId
                    );

            case "ytd_payout":

                return this.payoutHandler
                    .handleYTDPayout(
                        userId
                    );

            case "qtd_payout":

                return this.payoutHandler
                    .handleQTDPayout(
                        userId
                    );

            case "payout_components":

                return this.payoutHandler
                    .handlePayoutComponents(
                        userId
                    );

            case "breakdown":

                return this.payoutHandler
                    .handleBreakdown(
                        userId,
                        query
                    );

                // ==========================
                // QUOTA DOMAIN
                // ==========================

            case "quota":

                return this.quotaHandler
                    .handleQuota(
                        userId,
                        query
                    );

            case "quota_attainment":

                return this.quotaHandler
                    .handleQuotaAttainment(
                        userId
                    );

                // ==========================
                // PLAN DOMAIN
                // ==========================

            case "plan":

                return this.planHandler
                    .handlePlan(
                        userId
                    );

            case "plan_components":

                return this.planHandler
                    .handlePlanComponents(
                        userId
                    );

            case "lookup_rules":

                return this.planHandler
                    .handleLookupRules(
                        userId
                    );

            case "business_unit":

                return this.planHandler
                    .handleBusinessUnit(
                        userId
                    );

            default:

                this.utils.createFailureRecord(
                    query,
                    intent,
                    "IncentIQOrchestrator",
                    "Orchestrator",
                    "Intent not recognized",
                    "Now Assist",
                    userId
                );

                return "Intent not recognized.";
        }
    },

    type: 'IncentIQOrchestrator'
};
